// The Bhutanese woven pattern band — based on real label motifs
// Top + bottom rows: alternating diamonds + three-dot clusters with II dividers
// Middle row: lotus medallions with descending tendrils
function PatternBand({ color = C.gold, height = 36, opacity = 1, animate = true }) {
  // The traced strip from the real label: II + dice-5 cluster, repeating, bookended with II.
  // Implemented as a CSS-tileable SVG background-image for guaranteed responsive tiling
  // at any screen width. Animation = left-to-right wipe via clip-path.
  
  // SVG of ONE unit (II + dice-5), 32px wide × 32px tall, encoded as a data URI
  // Color is dynamic so we URL-encode it inline
  const unitSvg = encodeURIComponent(`
    <svg xmlns="http://www.w3.org/2000/svg" width="32" height="32" viewBox="0 0 32 32">
      <line x1="3" y1="6" x2="3" y2="26" stroke="${color}" stroke-width="2"/>
      <line x1="8" y1="6" x2="8" y2="26" stroke="${color}" stroke-width="2"/>
      <circle cx="18" cy="11" r="2.5" fill="${color}"/>
      <circle cx="26" cy="11" r="2.5" fill="${color}"/>
      <circle cx="22" cy="16" r="2.5" fill="${color}"/>
      <circle cx="18" cy="21" r="2.5" fill="${color}"/>
      <circle cx="26" cy="21" r="2.5" fill="${color}"/>
    </svg>
  `.trim());
  
  const bgImage = `url("data:image/svg+xml,${unitSvg}")`;
  
  return (
    <motion.div
      initial={animate ? { clipPath: 'inset(0 100% 0 0)' } : false}
      whileInView={animate ? { clipPath: 'inset(0 0% 0 0)' } : undefined}
      viewport={{ once: true, amount: 0.3 }}
      transition={{ duration: 0.9, ease: [0.22, 1, 0.36, 1] }}
      style={{
        height,
        opacity,
        position: 'relative',
        display: 'flex',
        alignItems: 'center',
      }}
    >
      {/* Top rule */}
      <div style={{
        position: 'absolute',
        top: '8%',
        left: 0,
        right: 0,
        height: 1.5,
        background: color,
      }} />
      
      {/* Pattern band — tiles horizontally edge to edge */}
      <div style={{
        position: 'absolute',
        top: '8%',
        bottom: '8%',
        left: 0,
        right: 16, /* leave room for closing II */
        backgroundImage: bgImage,
        backgroundRepeat: 'repeat-x',
        backgroundSize: `auto ${Math.max(height * 0.84, 20)}px`,
        backgroundPosition: 'left center',
      }} />
      
      {/* Closing II at the right end — using the same SVG as a positioned absolute element */}
      <svg
        width="12"
        height={height * 0.62}
        viewBox="0 0 12 20"
        xmlns="http://www.w3.org/2000/svg"
        style={{
          position: 'absolute',
          right: 0,
          top: '50%',
          transform: 'translateY(-50%)',
        }}
      >
        <line x1="3" y1="0" x2="3" y2="20" stroke={color} strokeWidth="2"/>
        <line x1="8" y1="0" x2="8" y2="20" stroke={color} strokeWidth="2"/>
      </svg>
      
      {/* Bottom rule */}
      <div style={{
        position: 'absolute',
        bottom: '8%',
        left: 0,
        right: 0,
        height: 1.5,
        background: color,
      }} />
    </motion.div>
  );
}

// The BHUTANESE wordmark — real artwork, tinted via CSS mask
function BhutaneseWordmark({ color = C.ink, height = 40, maxWidth = '100%' }) {
  return (
    <div
      role="img"
      aria-label="BHUTANESE"
      style={{
        display: 'block',
        height,
        aspectRatio: '5000 / 1150',
        maxWidth,
        backgroundColor: color,
        WebkitMaskImage: 'url(/images/IMG_6950.PNG)',
        maskImage: 'url(/images/IMG_6950.PNG)',
        WebkitMaskRepeat: 'no-repeat',
        maskRepeat: 'no-repeat',
        WebkitMaskSize: 'contain',
        maskSize: 'contain',
        WebkitMaskPosition: 'center',
        maskPosition: 'center',
      }}
    />
  );
}

// Dot-anchored divider line — matches label aesthetic
function DottedRule({ color = C.gold, className = '' }) {
  return (
    <div className={`flex items-center w-full ${className}`}>
      <div className="w-1.5 h-1.5 rounded-full" style={{ background: color }} />
      <div className="flex-1 h-px" style={{ background: color, opacity: 0.5 }} />
      <div className="w-1.5 h-1.5 rounded-full" style={{ background: color }} />
    </div>
  );
}

// Mono label — the spec-sheet voice
function Mono({ children, color, className = '' }) {
  return (
    <span
      className={`tracking-wider ${className}`}
      style={{ fontFamily: "'IBM Plex Mono', monospace", color: color || C.goldDeep }}
    >
      {children}
    </span>
  );
}

