// NAV
// ============================================================

function Nav({ page, setPage, dark }) {
  const [open, setOpen] = useState(false);
  const links = ['beers', 'bistro', 'visit', 'wholesale'];
  const bg = dark ? C.ink : C.paper;
  const text = dark ? C.bone : C.ink;
  const accent = dark ? C.gold : C.goldDeep;
  const border = dark ? C.lineLight : C.line;

  return (
    <nav
      className="sticky top-0 z-50 border-b backdrop-blur-md"
      style={{ background: dark ? 'rgba(13,13,13,0.92)' : 'rgba(239,233,216,0.92)', borderColor: border }}
    >
      <div className="px-5 sm:px-8 py-3.5 flex items-center justify-between">
        <button onClick={() => setPage('home')} className="flex items-center gap-3">
          <div style={{ height: 22 }}>
            <BhutaneseWordmark color={dark ? '#C9A96E' : C.ink} height={22} />
          </div>
        </button>

        <div className="hidden md:flex items-center gap-1">
          {links.map(slug => (
            <button
              key={slug}
              onClick={() => setPage(slug)}
              className="px-3.5 py-1.5 text-[10px] uppercase transition-colors"
              style={{
                fontFamily: "'IBM Plex Mono', monospace",
                color: text,
                background: page === slug ? (dark ? '#ffffff10' : '#00000008') : 'transparent',
                letterSpacing: '0.12em',
              }}
            >
              {page === slug && <span style={{ color: accent }}>● </span>}
              {slug.toUpperCase()}
            </button>
          ))}
        </div>

        <button className="md:hidden" onClick={() => setOpen(!open)} style={{ color: text }}>
          {open ? <X size={20} /> : <Menu size={20} />}
        </button>
      </div>

      <AnimatePresence>
        {open && (
          <motion.div
            initial={{ height: 0 }}
            animate={{ height: 'auto' }}
            exit={{ height: 0 }}
            transition={{ duration: 0.2 }}
            className="md:hidden overflow-hidden border-t"
            style={{ borderColor: border, background: bg }}
          >
            <div className="px-5 py-2 flex flex-col">
              {links.map(slug => (
                <button
                  key={slug}
                  onClick={() => { setPage(slug); setOpen(false); }}
                  className="text-left py-3 text-xs uppercase border-b"
                  style={{
                    color: text,
                    fontFamily: "'IBM Plex Mono', monospace",
                    borderColor: border,
                    letterSpacing: '0.18em',
                  }}
                >
                  → {slug}
                </button>
              ))}
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </nav>
  );
}

