function FormField({ label, value, onChange, type = 'text', multiline = false }) {
  return (
    <div>
      <div className="text-[9px] mb-1.5" style={{ fontFamily: "'IBM Plex Mono', monospace", color: C.gold, letterSpacing: '0.16em' }}>
        {label}
      </div>
      {multiline ? (
        <textarea
          value={value}
          onChange={(e) => onChange(e.target.value)}
          rows={3}
          className="w-full px-3 py-2.5 bg-transparent border focus:outline-none transition-colors text-sm"
          style={{
            borderColor: '#ffffff30',
            color: C.bone,
            fontFamily: "'IBM Plex Sans', sans-serif",
          }}
          onFocus={(e) => e.target.style.borderColor = C.gold}
          onBlur={(e) => e.target.style.borderColor = '#ffffff30'}
        />
      ) : (
        <input
          type={type}
          value={value}
          onChange={(e) => onChange(e.target.value)}
          className="w-full px-3 py-2.5 bg-transparent border focus:outline-none transition-colors text-sm"
          style={{
            borderColor: '#ffffff30',
            color: C.bone,
            fontFamily: "'IBM Plex Sans', sans-serif",
          }}
          onFocus={(e) => e.target.style.borderColor = C.gold}
          onBlur={(e) => e.target.style.borderColor = '#ffffff30'}
        />
      )}
    </div>
  );
}

// ============================================================
// APP
// ============================================================

export default function App() {
  const [page, setPage] = useState('home');

  useEffect(() => {
    window.scrollTo(0, 0);
  }, [page]);

  const darkNav = page === 'home' || page === 'wholesale';

  return (
    <div style={{ background: darkNav ? C.ink : C.paper, minHeight: '100vh' }}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Archivo+Black&family=IBM+Plex+Mono:wght@400;500;600&family=IBM+Plex+Sans:wght@300;400;500;600&family=Crimson+Pro:ital,wght@0,400;0,500;1,400;1,500&display=swap');
        body, html {
          font-family: 'IBM Plex Sans', system-ui, sans-serif;
          -webkit-font-smoothing: antialiased;
          background: ${darkNav ? C.ink : C.paper};
        }
        .scrollbar-none::-webkit-scrollbar { display: none; }
        .scrollbar-none { -ms-overflow-style: none; scrollbar-width: none; }
      `}</style>

      <Nav page={page} setPage={setPage} dark={darkNav} />

      <AnimatePresence mode="wait">
        <div key={page}>
          {page === 'home' && <HomePage setPage={setPage} />}
          {page === 'beers' && <BeersPage />}
          {page === 'bistro' && <BistroPage />}
          {page === 'visit' && <VisitPage />}
          {page === 'wholesale' && <WholesalePage />}
        </div>
      </AnimatePresence>
    </div>
  );
}
